#include<iostream>
#include <set>
#include <vector>
using namespace std;
int main()
{
    int t,n;
    cin>>t;
    for(int i=1;i<=t;i++)
    {
        cin>>n;
        set<int> s;
        vector<int> v;
        for(int j=1;j<=n;j++)
        {
            int k;
            cin>>k;
            if(s.find(k)==s.end())
            {
                s.insert(k);
                v.push_back(k);
            }
        }
        for(int j=0;j<=v.size()-1;j++)
        {
            cout<<v[j]<<' ';
        }
        cout<<endl;
    }

}
